void st75256_draw_hline(uint8_t *fb, int y) {
    if (y < 0 || y >= 160) return;
    int page = y / 8;
    int bit = y % 8;
    for (int x = 0; x < 256; x++) {
        fb[page * 256 + x] |= (1 << bit);
    }
}

void st75256_draw_char_ru(uint8_t *fb, int x, int page, uint16_t unicode) {
    int index = -1;
    if (unicode >= 32 && unicode <= 126) {
        index = unicode - 32;
    } else if (unicode >= 1040 && unicode <= 1103) {
        index = unicode - 1040 + 95;
    }

    if (index == -1) return;
    const uint8_t *glyph = font_cyrillic_data[index];

    for (int col = 0; col < 12; col++) {
        if (x + col >= 256) break;
        fb[page * 256 + x + col] = glyph[col];
        fb[(page + 1) * 256 + x + col] = glyph[col + 12];
    }
}

void st75256_draw_string_ru(uint8_t *fb, int x, int page, const char *str) {
    const uint8_t *p = (const uint8_t *)str;
    while (*p) {
        uint16_t unicode = 0;
        if (*p < 0x80) {
            unicode = *p++;
        } else if ((*p & 0xE0) == 0xC0) { // 2-byte UTF-8
            unicode = ((*p & 0x1F) << 6) | (*(p + 1) & 0x3F);
            p += 2;
        } else {
            p++; // Skip unsupported
            continue;
        }
        st75256_draw_char_ru(fb, x, page, unicode);
        x += 12;
    }
}

